sys_script_fix.script:
var gr_FormConfig = new GlideRecord('x_dtll2_contentint_platform_integration');

// See documentation to create the LIst View for the For Template Task, Shared Documents
// set the value of the Template Task list view below
//************************ SET ID HERE **********************************
// Get Template Task Shared Documents
var diTemplateTaskSharedDocuments = 'bcea3f28dbc324106a58ef92ca961951';
// ONCE YOU HAVE SET THE VALUE ABOVE, RUN THE SCRIPT
addFormConfig(diTemplateTaskSharedDocuments, 'Shared Documents',
				"Shared Documents Folder for Template Tasks in ServiceNow 'Service Portal' view in ServiceNow Portal.", "Portal Form",
				'2b11b40b4f650300d236eb118110c7f8', 'Default view', 'c7cb2e95db506810936dd498f4961955', 200,  'list_view_widget'
			);

// Get DocIntTaskViewID
var diTaskMyDocuments = gs.getProperty('x_153465_discovert.DocIntViewSysIDTasks');
addFormConfig(diTaskMyDocuments, 'My Documents',
				"My  Documents Folder for Tasks in ServiceNow 'Service Portal' view in ServiceNow Portal.", "Portal Form",
				'04a3cc064fa14300d236eb118110c7e3', 'Service Portal', 'e8ba5299db106810936dd498f4961926', 100,  'list_view_widget'
			);


// Get Task Shared Documents
var diTaskSharedDocuments = gs.getProperty('x_153465_discovert.DocIntSharedDocumentsViewSysIDTasks');
addFormConfig(diTaskSharedDocuments, 'Shared Documents',
				"Shared  Documents Folder for Tasks in ServiceNow 'Service Portal' view in ServiceNow Portal.", "Portal Form",
				'04a3cc064fa14300d236eb118110c7e3', 'Service Portal', 'e8ba5299db106810936dd498f4961926', 200,  'list_view_widget'
			);

// Get Template Shared Documents
var diTemplateSharedDocuments = gs.getProperty('x_153465_discovert.DocIntProcessSharedDocumentsViewSysIDTasks');
addFormConfig(diTemplateSharedDocuments, 'Shared Documents',
				"Shared  Documents Folder for Template Table in ServiceNow 'Service Portal' view in ServiceNow Portal.", "Portal Form",
				'9360300b4f650300d236eb118110c79f', 'Default view', '160bee55db506810936dd498f49619e2', 200,  'list_view_widget'
			);

// Get Template Shared Documents
var diTemplateTaskMydDocuments = gs.getProperty('x_153465_discovert.DocIntProcessTaskViewSysIDTasks');
addFormConfig(diTemplateTaskMydDocuments, 'My Documents',
				"My  Documents Folder for Tasks in ServiceNow 'Service Portal' view in ServiceNow Portal.", "Portal Form",
				'2b11b40b4f650300d236eb118110c7f8', 'Default view', 'c95c66d5db506810936dd498f49619b1', 100,  'list_view_widget'
			);

function addFormConfig(di_ViewID, display_name, description, integration_type, form_view, view_name, form_section, order, di_widget){

	gr_FormConfig.addEncodedQuery('docintegrator_view=' + di_ViewID + '^form_view=' + form_view);
	gr_FormConfig.query();

	if(!gr_FormConfig.next()){
		gr_FormConfig.initialize();
		gr_FormConfig.active = true;
		gr_FormConfig.display_name = display_name;
		gr_FormConfig.description = description;
		gr_FormConfig.integration_type = integration_type;
		gr_FormConfig.application = 'c6b1162d4fc10300303dc3818110c7b1';
		gr_FormConfig.form_view = form_view; // Service Portal ID for form, should be the same in every environment
		gr_FormConfig.view = view_name; // Service Portal name for form, should be the same in every environment
		gr_FormConfig.form_section = form_section; // ServiceNow Section ID, should be the same in every environment
		gr_FormConfig.order = order;

		gr_FormConfig.docintegrator_widget = di_widget;
		gr_FormConfig.docintegrator_view = di_ViewID;
		gr_FormConfig.portal = '6c4ef00b1bbdd8501a456288bd4bcb71';
		gr_FormConfig.insert('Tasker 2.7_Fix_Update_Document_Views');			
		gs.info('Tasker 2.7_Fix_Update_Document_Views - Form Configuration Name: [' + gr_FormConfig.display_name + "] - Form Configuration Description(***" + description + "***)");

	}
}
